    let x = 42;
    let v: Vec<i32> = vec![1, 2, 3];
    foo(x, &v);
}

fn foo<T>(a: T, b: &[T]) -> ()
where
    T: Copy + std::ops::Add<Output = T>
{ // Use where clause to constrain the types
    println!("{}", a + b[0]);
}
```

